sts = ["accept", "reject", "accept"]
n_accept = n_reject = n_total = 0
for s in sts:
    n_total += 1
    if s == "accept":
        n_accept += 1
    elif s == "reject":
        n_reject += 1
print(n_accept, n_reject, n_total)

def tasa_reject(sts):
    n_total = len(sts)
    if n_total == 0:
        return None
    n_reject = 0
    for s in sts:
        if s == "reject":
            n_reject += 1
    return n_reject / n_total
print(tasa_reject(["accept", "reject", "accept"]))
print(tasa_reject([]))

